CREATE TYPE "KeywordRole" AS ENUM ('DISCOVERY','CONTEXT','SIGNAL','EXCLUSION');
CREATE TYPE "KeywordSource" AS ENUM ('MANUAL','IMPORT','SYSTEM_SUGGESTED','API');
CREATE TYPE "KeywordStatus" AS ENUM ('DRAFT','ACTIVE','PAUSED','ARCHIVED','DELETED');
CREATE TYPE "MatchMode" AS ENUM ('EXACT','PHRASE','CONTAINS');
CREATE TYPE "ReferenceStatus" AS ENUM ('ACTIVE','ARCHIVED');
CREATE TABLE "keyword_categories" ("id" UUID NOT NULL, "code" VARCHAR(64) NOT NULL, "name" VARCHAR(120) NOT NULL, "parent_id" UUID, "status" "ReferenceStatus" NOT NULL DEFAULT 'ACTIVE', "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL, CONSTRAINT "keyword_categories_pkey" PRIMARY KEY ("id"));
CREATE TABLE "keyword_tags" ("id" UUID NOT NULL, "code" VARCHAR(64) NOT NULL, "name" VARCHAR(120) NOT NULL, "status" "ReferenceStatus" NOT NULL DEFAULT 'ACTIVE', "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL, CONSTRAINT "keyword_tags_pkey" PRIMARY KEY ("id"));
CREATE TABLE "keywords" ("id" UUID NOT NULL, "phrase" VARCHAR(120) NOT NULL, "normalized_phrase" VARCHAR(160) NOT NULL, "category_id" UUID NOT NULL, "source" "KeywordSource" NOT NULL, "status" "KeywordStatus" NOT NULL DEFAULT 'DRAFT', "match_mode" "MatchMode" NOT NULL, "note" VARCHAR(500), "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL, "archived_at" TIMESTAMPTZ(3), "deleted_at" TIMESTAMPTZ(3), CONSTRAINT "keywords_pkey" PRIMARY KEY ("id"));
CREATE TABLE "keyword_roles" ("keyword_id" UUID NOT NULL, "role" "KeywordRole" NOT NULL, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "keyword_roles_pkey" PRIMARY KEY ("keyword_id","role"));
CREATE TABLE "keyword_variants" ("id" UUID NOT NULL, "keyword_id" UUID NOT NULL, "phrase" VARCHAR(120) NOT NULL, "normalized_phrase" VARCHAR(160) NOT NULL, "status" "ReferenceStatus" NOT NULL DEFAULT 'ACTIVE', "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL, CONSTRAINT "keyword_variants_pkey" PRIMARY KEY ("id"));
CREATE TABLE "keyword_tag_links" ("keyword_id" UUID NOT NULL, "tag_id" UUID NOT NULL, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "keyword_tag_links_pkey" PRIMARY KEY ("keyword_id","tag_id"));
CREATE UNIQUE INDEX "keyword_categories_code_key" ON "keyword_categories"("code"); CREATE UNIQUE INDEX "keyword_tags_code_key" ON "keyword_tags"("code"); CREATE UNIQUE INDEX "keywords_normalized_phrase_key" ON "keywords"("normalized_phrase"); CREATE UNIQUE INDEX "keyword_variants_keyword_id_normalized_phrase_key" ON "keyword_variants"("keyword_id","normalized_phrase");
CREATE INDEX "keyword_categories_parent_id_idx" ON "keyword_categories"("parent_id"); CREATE INDEX "keyword_categories_status_idx" ON "keyword_categories"("status"); CREATE INDEX "keyword_tags_status_idx" ON "keyword_tags"("status"); CREATE INDEX "keywords_category_id_idx" ON "keywords"("category_id"); CREATE INDEX "keywords_status_idx" ON "keywords"("status"); CREATE INDEX "keywords_source_idx" ON "keywords"("source"); CREATE INDEX "keywords_updated_at_idx" ON "keywords"("updated_at" DESC); CREATE INDEX "keyword_roles_role_idx" ON "keyword_roles"("role"); CREATE INDEX "keyword_variants_keyword_id_idx" ON "keyword_variants"("keyword_id"); CREATE INDEX "keyword_variants_status_idx" ON "keyword_variants"("status"); CREATE INDEX "keyword_tag_links_tag_id_idx" ON "keyword_tag_links"("tag_id");
ALTER TABLE "keyword_categories" ADD CONSTRAINT "keyword_categories_parent_id_fkey" FOREIGN KEY ("parent_id") REFERENCES "keyword_categories"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "keywords" ADD CONSTRAINT "keywords_category_id_fkey" FOREIGN KEY ("category_id") REFERENCES "keyword_categories"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "keyword_roles" ADD CONSTRAINT "keyword_roles_keyword_id_fkey" FOREIGN KEY ("keyword_id") REFERENCES "keywords"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "keyword_variants" ADD CONSTRAINT "keyword_variants_keyword_id_fkey" FOREIGN KEY ("keyword_id") REFERENCES "keywords"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "keyword_tag_links" ADD CONSTRAINT "keyword_tag_links_keyword_id_fkey" FOREIGN KEY ("keyword_id") REFERENCES "keywords"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "keyword_tag_links" ADD CONSTRAINT "keyword_tag_links_tag_id_fkey" FOREIGN KEY ("tag_id") REFERENCES "keyword_tags"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
